const repos = ["acme/infra", "acme/web", "acme/api", "acme/mobile"];
const allMerged = repos.flatMap(r => github.list_pull_requests({ repo: r, state: "merged" }));
const sample = allMerged[0];
const keys = sample ? Object.keys(sample) : [];
({ count: allMerged.length, keys, sample });
"}

{"code":"
const closing = allMerged.filter(pr => pr.closes_linear);
closing.map(pr => ({ repo: pr.repo, number: pr.number, title: pr.title, closes_linear: pr.closes_linear }));
"}

{"code":"
const results = closing.map(pr => {
  const title = "Verify: " + pr.title;
  const body = `Opened automatically for merged PR ${pr.repo}#${pr.number} (closes ${pr.closes_linear}).`;
  const created = github.create_issue({ repo: "acme/web", title, body });
  return { src: `${pr.repo}#${pr.number}`, linear: pr.closes_linear, title, issue: created };
});
results;
"}
